 5→interface TransactionItemProps extends SDUIComponentProps {
 6→  icon: string;
 7→  title: string;
 8→  value: string;
 9→  valueColor?: string;
10→  typeLabel?: string;
11→  showIcon?: boolean;
12→  mb?: string;
13→}
14→
15→const VALUE_COLOR_MAP: Record<string, string> = {
16→  green: 'ACCEPT_COLOR_01',
17→  red: 'DENY_COLOR_01',
18→  gray: 'INTENSE_COLOR_03',
19→  orange: 'ALERT_COLOR_01',
20→};
21→
22→export default function TransactionItemAdapter({
23→  props,
24→}: {
25→  props: TransactionItemProps;
26→  context: SDUIContext;
27→}) {
28→  const {
29→    icon,
30→    title,
31→    value,
32→    valueColor = 'green',
33→    typeLabel,
34→    showIcon = true,
35→    mb = 'xxxs',
36→  } = props;
37→
38→  const resolvedColor = VALUE_COLOR_MAP[valueColor] ?? valueColor;
39→
40→  return (
41→    <Box
42→      direction
43→      pd="squishSmall"
44→      mb={mb}
45→      align="center"
46→      bgColor="LIGHT_BASE_01"
47→      br="sm"
48→      style={{ minHeight: 56 }}
49→    >
50→      {showIcon && (
51→        <Box
52→          width={36}
53→          height={36}
54→          align="center"
55→          justify="center"
56→          bgColor="BRAND_COMPLEMENT_02"
57→          mr="xxxs"
58→          style={{ borderRadius: 18 }}
59→        >
60→          <Icon name={String(icon)} size="sm" color="INTENSE_COLOR_05" />
61→        </Box>
62→      )}
63→      <Box flex={1}>
64→        <Text type="paragraphMDM" numberOfLines={1}>
65→          {title}
66→        </Text>
67→        {typeLabel ? (
68→          <Text type="captionSM" color="INTENSE_COLOR_03">
69→            {typeLabel}
70→          </Text>
71→        ) : null}
72→      </Box>
73→      <Box align="flex-end">
74→        <Text type="paragraphMDM" color={resolvedColor}>
75→          {value}
76→        </Text>
77→      </Box>
78→    </Box>
79→  );
80→}
