 1→import type { SDUIContext, SDUIContextValue } from '../models';
 2→
 3→const INTERPOLATION_REGEX = /\{\{([^}]+)\}\}/g;
 4→const DENIED_KEYS = new Set(['__proto__', 'constructor', 'prototype']);
 5→
 6→export function resolveContextPath(
 7→  context: SDUIContext,
 8→  path: string,
 9→): SDUIContextValue {
10→  const segments = path.trim().split('.');
11→  let current: SDUIContextValue = context;
12→
13→  for (const segment of segments) {
14→    if (current === null || current === undefined) return '';
15→    if (typeof current !== 'object') return '';
16→    if (DENIED_KEYS.has(segment)) return '';
17→
18→    if (Array.isArray(current)) {
19→      const index = parseInt(segment, 10);
20→      if (isNaN(index) || index < 0 || index >= current.length) return '';
21→      current = current[index] as SDUIContextValue;
22→    } else {
23→      current = (current as SDUIContext)[segment];
24→    }
25→  }
26→
27→  return current ?? '';
28→}
29→
30→export function interpolateString(
31→  template: string,
32→  context: SDUIContext,
33→): string {
34→  return template.replace(INTERPOLATION_REGEX, (_, path: string) => {
35→    const value = resolveContextPath(context, path);
36→    if (value === null || value === undefined) return '';
37→    if (typeof value === 'object') return '';
38→    return String(value);
39→  });
40→}
41→
42→export function interpolateDeep<T>(value: T, context: SDUIContext): T {
43→  if (typeof value === 'string') {
44→    return interpolateString(value, context) as T;
45→  }
46→
47→  if (Array.isArray(value)) {
48→    return value.map(item => interpolateDeep(item, context)) as T;
49→  }
50→
51→  if (value !== null && typeof value === 'object') {
52→    const result: Record<string, unknown> = {};
53→    for (const key of Object.keys(value)) {
54→      result[key] = interpolateDeep(
55→        (value as Record<string, unknown>)[key],
56→        context,
57→      );
58→    }
59→    return result as T;
60→  }
61→
62→  return value;
63→}
